if (nrow(predictions) &gt; 0 && requireNamespace("ggplot2", quietly = TRUE)) {
  wide_plot_data &lt;- predictions |&gt;
    dplyr::filter(is.na(home_score), is.na(away_score)) |&gt;
    dplyr::mutate(match = paste(home_team, "vs", away_team)) |&gt;
    dplyr::arrange(date, source_match_id) |&gt;
    dplyr::slice_head(n = 12) |&gt;
    dplyr::mutate(
      home_public_prob = dplyr::if_else(is_knockout_match, home_advance_prob, pred_home_win_prob),
      middle_public_prob = dplyr::if_else(is_knockout_match, regulation_draw_prob, pred_draw_prob),
      away_public_prob = dplyr::if_else(is_knockout_match, away_advance_prob, pred_away_win_prob),
      middle_label = dplyr::if_else(is_knockout_match, "Level after regulation", "Draw"),
      home_label = dplyr::if_else(is_knockout_match, "Home advances", "Home win"),
      away_label = dplyr::if_else(is_knockout_match, "Away advances", "Away win")
    ) |&gt;
    dplyr::select(match, home_public_prob, middle_public_prob, away_public_prob, home_label, middle_label, away_label)

  plot_data &lt;- rbind(
    data.frame(match = wide_plot_data$match, outcome = wide_plot_data$home_label, probability = wide_plot_data$home_public_prob),
    data.frame(match = wide_plot_data$match, outcome = wide_plot_data$middle_label, probability = wide_plot_data$middle_public_prob),
    data.frame(match = wide_plot_data$match, outcome = wide_plot_data$away_label, probability = wide_plot_data$away_public_prob)
  )
  plot_data$match &lt;- factor(plot_data$match, levels = rev(unique(wide_plot_data$match)))

