      "Level after regulation" = "#d9a441",
      "Away win" = "#b85c5c",
      "Away advances" = "#b85c5c"
    )) +
    ggplot2::labs(
      title = "Fixture public probabilities",
      x = "Predicted probability",
      y = NULL,
      fill = NULL
    ) +
    ggplot2::theme_minimal(base_size = 12)
